{
  "options": [
    {
      "text": "“我不是她的人。我只是来找人的。”",
      "actionId": "choice:alt-02_respond_deny"
    },
    {
      "text": "“你和她之间有什么过节？既然她知道你会在这里。”",
      "actionId": "choice:alt-02_ask_grudge"
    },
    {
      "text": "保持沉默，站在原地等她先打破僵局。",
      "actionId": "choice:alt-02_observe_silence"
    }
  ]
}
